eventScript.func:
setTimeout(async () => {


    const maxRetries = 10;
    const interval = 500;
    for (let i = 0; i < maxRetries; i++) {
        const op = await this.onDropdownVisible('reload_invoice_no_type', true);
        if (op != null) break;
        await new Promise(resolve => setTimeout(resolve, interval));
    }
    function getDefaultItem(arr) {
        return arr?.find(item => item?.item?.is_default === 1);
    }
    var params = this.getComponent('reload_invoice_no');
    const { options } = params;

    const optionsData = this.getOptionData('reload_invoice_no_type') || [];
    const defaultData = getDefaultItem(optionsData);
    if(options?.canManualInput) {
        this.setOptionData("reload_invoice_no_type", [{label: 'Manual Input', value: -9999}, ...optionsData]);
        if (this.isAdd) {
            this.setData({ reload_invoice_no_type: defaultData ? defaultData.value : -9999 });
        }
    } else if (defaultData) {
      if (this.isAdd) {
          this.setData({ reload_invoice_no_type:defaultData.value})
      }
    }
  }, 200)

(async () => {
  try {
    const item = arguments[0]?.fieldModel?.item;
    if (!item) return;

    // Scalars come straight off the selected customer row - no fetch needed.
    this.setData({
      customer_name: item.customer_com_name || '',
      customer_reg_no: item.customer_com_reg_no || '',
      customer_tax_no: item.customer_tin_no || '',
      payment_term: item.customer_payment_term_id || null,
      sub_remain_before: item.sub_remain_credit || 0,
      reload_remain_before: item.reload_remain_credit || 0,
    });

    // --- billing address ---------------------------------------------------
    const addressList = item.address_list;

    if (Array.isArray(addressList) && addressList.length > 0) {
      const resBilling = await db
        .collection('address_purpose')
        .where({ purpose_name: 'Billing' })
        .get();

      // address_purpose is a global reference table - a missing row must not throw.
      const billingPurposeId = resBilling?.data?.[0]?.id;

      const billing =
        (billingPurposeId &&
          addressList.find(
            (address) =>
              address.address_purpose_id === billingPurposeId &&
              address.switch_save_as_default
          )) ||
        (billingPurposeId &&
          addressList.find(
            (address) => address.address_purpose_id === billingPurposeId
          )) ||
        addressList[0];

      if (billing) {
        // address_country_id / adddress_state are id-bound selects on this form
        // too, so the raw ids copy across without a name lookup.
        this.setData({
          address_name: billing.address_name || '',
          address_country_id: billing.address_country_id || null,
          adddress_state: billing.adddress_state || null,
          address_line_1: billing.address_line_1 || '',
          address_line_2: billing.address_line_2 || '',
          address_line_3: billing.address_line_3 || '',
          address_line_4: billing.address_line_4 || '',
          address_city: billing.address_city || '',
          address_postal_code: billing.address_postal_code || '',
          address_phone: billing.address_phone || '',
          address_phone2: billing.address_phone2 || '',
          address_mobile: billing.address_mobile || '',
          address_email: billing.address_email || '',
        });
      }
    } else {
      console.warn('Credit Reload: customer row carried no address_list', item);
    }

    // --- currency ----------------------------------------------------------
    // Re-set through '' so currency_id's onChange fires even when the new
    // customer happens to share the previous customer's currency.
    await this.setData({ currency_id: '' });
    await this.setData({ currency_id: item.customer_currency_id || null });
  } catch (error) {
    console.error('Credit Reload: failed to load customer', error);
    this.$message.error('Failed to load customer details.');
  }
})();

(async () => {
  const RATE_FIELDS = [
    'exchange_rate',
    'exchange_rate_myr',
    'exchange_rate_currency',
    'total_amount_myr',
  ];

  try {
    const currencyId = this.getValue('currency_id');

    if (!currencyId) {
      this.setData({ exchange_rate: 1, exchange_rate_currency: '', exchange_rate_myr: 'MYR' });
      this.hide(RATE_FIELDS);
      this.triggerEvent('func_recalc');
      return;
    }

    const resCurrency = await db.collection('currency').where({ id: currencyId }).get();
    const currencyEntry = resCurrency?.data?.[0];

    if (!currencyEntry) {
      console.warn('Credit Reload: currency not found', currencyId);
      this.triggerEvent('func_recalc');
      return;
    }

    const currencyCode = currencyEntry.currency_code;

    if (currencyCode && currencyCode !== 'MYR' && currencyCode !== '----') {
      // Foreign currency - the buying rate converts document currency into MYR.
      this.setData({
        exchange_rate: currencyEntry.currency_buying_rate || 1,
        exchange_rate_currency: currencyCode,
        exchange_rate_myr: 'MYR',
      });
      this.display(RATE_FIELDS);
    } else {
      // Already base currency - the MYR total would just duplicate total_amount.
      this.setData({
        exchange_rate: 1,
        exchange_rate_currency: currencyCode || '',
        exchange_rate_myr: 'MYR',
      });
      this.hide(RATE_FIELDS);
    }

    this.triggerEvent('func_recalc');
  } catch (error) {
    console.error('Credit Reload: failed to load currency', error);
    this.$message.error('Failed to load currency exchange rate.');
  }
})();

// Single source of truth for every computed amount on this form.
// Pricing is hardcoded for now - BASE_AMOUNT of document currency buys BASE_CREDIT credits.
const BASE_AMOUNT = 45;
const BASE_CREDIT = 10000;
const TAX_RATE = 0.08;

const round = (value, dp) => parseFloat(parseFloat(value || 0).toFixed(dp));

const data = this.getValues();

const reloadAmount = parseFloat(data.reload_amount) || 0;
const exchangeRate = parseFloat(data.exchange_rate) || 1;
const reloadType = data.reload_type;
const subBefore = parseFloat(data.sub_remain_before) || 0;
const reloadBefore = parseFloat(data.reload_remain_before) || 0;

// Credits scale linearly with the amount paid. ai_credit_reload_amount is an
// int column (precision 0), so round rather than truncate.
const credits = Math.round((reloadAmount / BASE_AMOUNT) * BASE_CREDIT);

// Tax is exclusive - added on top of the entered amount.
const totalGross = round(reloadAmount, 2);
const totalTax = round(totalGross * TAX_RATE, 2);
const totalAmount = round(totalGross + totalTax, 2);
const totalAmountMyr = round(totalAmount * exchangeRate, 2);

// Monthly Subscription RESETS the subscription balance to the purchased credits,
// ignoring whatever was left. Add On accumulates onto the reload balance.
// Anything else leaves both balances untouched.
let subAfter = subBefore;
let reloadAfter = reloadBefore;

if (reloadType === 'Monthly Subscription') {
  subAfter = credits;
} else if (reloadType === 'Add On') {
  reloadAfter = reloadBefore + credits;
}

this.setData({
  ai_credit_reload_amount: credits,
  total_gross: totalGross,
  total_tax_amount: totalTax,
  total_amount: totalAmount,
  total_amount_myr: totalAmountMyr,
  sub_remain_after: subAfter,
  reload_remain_after: reloadAfter,
});

// Default the amount to one standard package. Keep in step with
// BASE_AMOUNT in func_recalc.
this.setData({ reload_amount: 45 });
this.triggerEvent('func_recalc');

